# ── Binary Tree Splay (Roll-Up) ───────────────────────────────────────────────
# Interactive mode only — there is no algorithm to trace.
# After clicking Analyze, click "go to interactive mode" to start.
#
# Click any node to splay (roll up) it toward the root via tree rotations.
# Green nodes are balanced (|left_height − right_height| ≤ 1); red are not.
# Height is shown in brackets below each key.
# ─────────────────────────────────────────────────────────────────────────────
class Node:

    @staticmethod
    def ht(node: 'Node'):
        return -1 if node is None else node.height

    def __init__(self, key: int):
        self.key = key
        self.parent = None 
        self.left = None
        self.right = None
        self.height = 0

        # @viz
        self._viz = VizNode(self)
        # @end


    def __str__(self):
        left_str = '' if self.left is None else str(self.left)
        right_str = '' if self.right is None else str(self.right)
        if len(left_str) + len(right_str) == 0:
            return str(self.key)
        else:
            return f'{self.key}({left_str},{right_str})'

    def update_height(self):
        self.height = 1 + max( 
            -1 if self.left is None else self.left.height,
            -1 if self.right is None else self.right.height)
        # @viz
        self._viz.set_label(f'{self.key}\n[{self.height}]')
        # @end

    def set_child(self, node: 'Node', left_side: bool):
        if left_side:
            self.left = node
        else:
            self.right = node
        if node is not None:
            node.parent = self
            # @viz
            node._viz.edge.start = self._viz.edge.end
            # @end

    def roll_up(self):
        if self.parent is None:
            return

        parent = self.parent
        grandparent = parent.parent
        if grandparent is not None:
            if grandparent.left is parent:
                grandparent.set_child(self, left_side = True)
            else:
                grandparent.set_child(self, left_side = False)
        else:
            self.parent = None

        if parent.left is self:
            child = self.right
            self.set_child(parent, left_side = False)
            parent.set_child(child, left_side = True)
        else:
            child = self.left
            self.set_child(parent, left_side = True)
            parent.set_child(child, left_side = False)

        parent.update_height()
        self.update_height()


class Tree:

    @staticmethod
    def parse_tree(rep: str) -> 'Tree':
        """
        Parse strings like A(B(C,D),E(F,)) into a tree.
        Brackets with comma (,) are use to show the children. There should
        always be just one comma, and the left \ right sides can be left empty.
        """
        def _parse_tree(rep: str, index: int) -> tuple[Node, int]:
            route = []
            key_str = []
            left_child = True
            while index < len(rep) and rep[index] not in ('(',')',','):
                key_str.append(rep[index])
                index += 1

            if index < len(rep) and rep[index] == '(':

                if len(key_str) == 0:
                    raise PopupException(f'empty key at index {rep}[{index}] ')   
                key = int(''.join(key_str))
                node = Node(key)

                left, index = _parse_tree(rep, index+1)
                node.set_child(left, left_side=True)

                if rep[index] != ',':
                    raise PopupException(f'key {key} doesn\'t have 2 children in {rep}')

                right, index = _parse_tree(rep, index+1)
                node.set_child(right, left_side=False)

                if rep[index] != ')':
                    raise PopupException(f'key {key} doesn\'t have closing bracket in {rep}')
                node.update_height()
                return node, index+1
            else:   # found just ',', ')' or end of string
                if len(key_str) == 0:
                    return None, index

                node = Node(int(''.join(key_str)))
                node.update_height()
                return node, index
        root, _ = _parse_tree(rep, 0)
        return Tree(root)


    def __init__(self, root: Node):
        self.root = root

        # @viz
        self._viz = VizTree(self)
        # @end

    def roll_up(self, node: Node):
        node.roll_up()
        if node.parent is None:
            self.root = node
        else:
            while node.parent is not None:
                node = node.parent
                node.update_height()
        # @viz
        self._viz.redraw()
        # @end




