from graphs import compute_rel_positions

class VizNode:
    def __init__(self, node: Node):
        self.node = node
        self.edge = Line(end_offset=(0.5,0), z=1)
        self.btn = LabeledButton(label=f'{node.key}', color=[0,100,50], on_click=lambda x,y: print(1))

    def set_position(self, x: int, y: int):
        self.btn.x = x
        self.btn.y = y
        self.edge.end = (y, x)
        if self.node.left is not None:
            self.node.left._viz.edge.start = (y, x)
        if self.node.right is not None:
            self.node.right._viz.edge.start = (y, x)

    def set_color(self, color: tuple[int, int, int]):
        self.btn.rect.color = color

    def set_label(self, label: str):
        self.btn.label.label = label

    def set_on_click(self, on_click: callable):
        self.btn.set_on_click(on_click)

class VizTree:
    def __init__(self, tree: Tree):
        self.tree = tree

        def _on_click(node: Node):
            if node is None:
                return
            node._viz.set_on_click(lambda x,y: no_debug(tree.roll_up)(node))
            _on_click(node.left)
            _on_click(node.right)

        _on_click(tree.root)

        self.redraw()

    def to_dict(self):
        def _to_dict(node: Node):
            if node is None:
                return
            tree_dict[node] = (node.left, node.right)
            _to_dict(node.left)
            _to_dict(node.right)
        tree_dict = {}
        _to_dict(self.tree.root)
        return tree_dict

    def redraw(self, position: tuple[int,int] | None = None):

        def _draw_dict(node: Node, position: tuple[int, int], rel_x: dict):
            if node is None:
                return
            node._viz.set_position(position[1], position[0])
            if abs(Node.ht(node.left) - Node.ht(node.right)) <= 1:
                node._viz.set_color((0,100,50))
            else:
                node._viz.set_color((200,50,0))
            _draw_dict(node.left, (position[0]+2, position[1]+rel_x[node.left]), rel_x)
            _draw_dict(node.right, (position[0]+2, position[1]+rel_x[node.right]), rel_x)

        rel_x = compute_rel_positions(self.to_dict(), self.tree.root)
        rel_x[None] = 0

        if position is None:
            position = (1, 7)
        self.tree.root._viz.edge.start = position
        _draw_dict(self.tree.root, position, rel_x)


class LabeledButton(Panel):
    def __init__(self, label: str, color: tuple[int,int,int] = (220,140,160), on_click: callable  = None, **kwargs):
        super().__init__(**kwargs)
        self.rect = Rect(color=color)
        self.rect.on_click = on_click
        self.label = Label(label=label)
        self.add(self.label, self.rect)

    def set_on_click(self, on_click: callable):
        self.rect.on_click = on_click

